import { Component } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { AngularEditorConfig } from '@kolkov/angular-editor';
import { ApiService } from '@services/api.service';
import { environment as env } from 'environments/environment';
import { ToastrService } from 'ngx-toastr';
import { catchError } from 'rxjs';

@Component({
  selector: 'app-page-details',
  templateUrl: './page-details.component.html',
  styleUrls: ['./page-details.component.scss']
})
export class PageDetailsComponent {

  page_id: string;
  pageForm: FormGroup;
  page : Page;
  pageContent: string;

  editorConfig: AngularEditorConfig = {
    editable: true,
    spellcheck: true,
    height: '300px',
    minHeight: '300px',
    maxHeight: 'auto',
    width: 'auto',
    minWidth: '0',
    translate: 'yes',
    enableToolbar: true,
    showToolbar: true,
    placeholder: 'Enter content here...',
    defaultParagraphSeparator: '',
    defaultFontName: '',
    defaultFontSize: '',
    fonts: [
      { class: 'arial', name: 'Arial' },
      { class: 'times-new-roman', name: 'Times New Roman' },
      { class: 'calibri', name: 'Calibri' },
      { class: 'comic-sans-ms', name: 'Comic Sans MS' }
    ],
    customClasses: [

    ],
    uploadUrl: `${env.BASE_PATH}/api/v1/file/upload/image/public`,
    uploadWithCredentials: false,
    sanitize: true,
    toolbarPosition: 'top',
    toolbarHiddenButtons: [
      [],
      ['insertVideo']
    ]
  };


  constructor(
    private api: ApiService, 
    private route: ActivatedRoute,
    private toastr: ToastrService,
    private fb: FormBuilder,
    private router: Router
  ) {

    this.pageForm = this.fb.group({
      slug: ['', [Validators.required]],
      page_title: ['', [Validators.required]],
      page_content: ['', [Validators.required]],
      is_system_page: ['', [Validators.required]]
    })

    this.route.params.subscribe((p: any) => {
      this.page_id = p.page_id;
      this.getPageDetails();
    })
  }

  getPageDetails() {
    const sub = this.api.getPageDetails(this.page_id).subscribe((response: any) => {
      sub.unsubscribe();
      this.pageContent = response.page.page_content;
      this.page = {
        slug: response.page.slug,
        page_title: response.page.page_title,
        page_content: response.page.page_content,
        is_system_page: response.page.is_system_page,
      }
      this.pageForm.setValue(this.page);
    })
  }


  updatePage() {
    const slug = this.pageForm.value.slug;
    const page_title = this.pageForm.value.page_title;
    const page_content = this.pageForm.value.page_content;
    const is_system_page = this.pageForm.value.is_system_page;

    const sub = this.api.updatePageDetails(this.page_id, slug, page_title, page_content, is_system_page)
    .pipe(
      catchError(err => {
        sub.unsubscribe();
        this.toastr.error(err.message);
        return err;
      })
    )
    .subscribe((response: any) => {
      sub.unsubscribe();
      this.toastr.success(response?.message);
    })

  }


  deletePage() {
    const sub = this.api.deletePage(this.page_id)
    .pipe(
      catchError(err => {
        return err;
      })
    )
    .subscribe((response: any) => {
      sub.unsubscribe();
      if(response?.status >= 400) {
        this.toastr.error(response.error.message)
        return;
      }
      this.toastr.success(response.message);
      this.router.navigate(['/pages']);
    })
  }


}




interface Page{
  slug: string;
  page_title: string;
  page_content: string;
  is_system_page: boolean;
}